-- SQL de tabela única gerado a partir da aba PLANILHA MODELO
-- Compatível com PostgreSQL / Supabase

DROP TABLE IF EXISTS public.controle_ausencias_excel;

CREATE TABLE public.controle_ausencias_excel (
    id BIGSERIAL PRIMARY KEY,
    nome TEXT NOT NULL,
    email TEXT,
    funcao TEXT,
    lider_direto TEXT,
    superior TEXT,
    data_admissao DATE,
    ano_aquisitivo_inicio INTEGER,
    ano_aquisitivo_termino INTEGER,
    inicio_periodo_aquisitivo DATE,
    fim_periodo_aquisitivo DATE,
    limite_ausencia_efetiva DATE,
    saldo NUMERIC(10,2),
    quantidade_dias_ausencia_programada NUMERIC(10,2),
    inicio_ausencia DATE,
    fim_ausencia DATE,
    dias_pendentes INTEGER,
    status TEXT
);

CREATE INDEX idx_controle_ausencias_excel_nome ON public.controle_ausencias_excel (nome);
CREATE INDEX idx_controle_ausencias_excel_status ON public.controle_ausencias_excel (status);
CREATE INDEX idx_controle_ausencias_excel_lider_direto ON public.controle_ausencias_excel (lider_direto);
CREATE INDEX idx_controle_ausencias_excel_superior ON public.controle_ausencias_excel (superior);
CREATE INDEX idx_controle_ausencias_excel_periodo ON public.controle_ausencias_excel (inicio_periodo_aquisitivo, fim_periodo_aquisitivo);

